INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '个区域。该实验室采购了一台具有 VLAN 功能的两层交换机， 用于搭建实验室有线局域网，实现三个项目组的网络隔离。初期考虑到项目组位置固定，且有一定的 人员流动，搭建实验室局域网时宜采用的 VLAN 划分方法是(38) 。 随着项目进展及人员流动加剧，项目组区域己经不再适合基于区域聚集原则进行划分，而且项目组长 或负责人也需要能够同时加入到不同的VLAN 中。此时宣采用的VLAN 划分方法是(39) 。 在项目后期阶段，三个项目组需要进行联合调试，因此需要实现三个VLAN 间的互联互通。目前有两 种方案: 方案一:采用独立路由器方式，保留两层交换机，增加一个路由器。 方案二:采用三层交换机方式，用带 VLAN 功能的三层交换机替换原来的两层交换机。 与方案一相比， 下列叙述中不属于方案二优点的是(40) 。 (40) A. VLAN 间数据帧要被解封成 IP 包再进行传递', '["B. 基于 MAC 地址", "C. 基于网络地址", "D. 基于 IP组播", "B. 三层交换机具有路由功能，可以直接实现多个 VLAN之间的通信"]', '', '', 2, '2015年综合知识', '2015,综合知识', 2015);
