INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '5、在磁盘上存储数据的排列方式会影响 1/0 服务的总时间。假设每磁道划分成 10 个物理块，每块 存放 1 个逻辑记录: 逻辑记录 R1，R2，…，R10 存放在同一个磁道上，记录的安排顺序如下表所示: | mee | 二| 2 | 3 45 | 6 | 7 | 8 | 98 | 10 | a RTMTTR|NT Rn 假定磁盘的旋转速度为 30ms/周，磁头当前处在 RI 的开始处。若系统顺序处理这些记录，使用单缓冲 区，每个记录处理时间为 ns，则处理这 10 个记录的最长时间为《4) ; 若对信息存储进行优化分布 后，处理 10 个记录的最少时间为 (5) 。', '["C. 289ms", "D. 306ms", "B. 90ms", "C. 109ms"]', '', '', 2, '2015年综合知识', '2015,综合知识', 2015);
